from typing import List
class Solution:
    def findDuplicate(self, paths: List[str]) -> List[List[str]]:
        content_dict = {}
        for path in paths:
            dir, *files = path.split(' ')
            for file in files:
                name, content = file.split('(')
                if content in content_dict:
                    content_dict[content].append(dir + '/' + name)
                else:
                    content_dict[content] = [dir + '/' + name]
        return [v for v in content_dict.values() if len(v) > 1]
```

